#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int type;
        scanf("%d", &type);
        char s[100005];
        scanf("%s", s);
        int n = strlen(s);
        int boys = 0, girls = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 'B') boys++;
            else girls++;
        }
        if (abs(boys - girls) > 1) {
            printf("-1\n");
            continue;
        }
        int cost = 0;
        for (int i = 0; i < n; i++) {
            if (i % 2 == 0 && s[i] != 'B' || i % 2 == 1 && s[i] != 'G') {
                for (int j = i + 1; j < n; j++) {
                    if (i % 2 == 0 && s[j] == 'B' || i % 2 == 1 && s[j] == 'G') {
                        char temp = s[i];
                        s[i] = s[j];
                        s[j] = temp;
                        if(type == 1) cost += (j - i);
                        else if(type == 2) cost += (j - i) * (j - i);
                        break;
                    }
                }
            }
        }
        printf("%d\n", cost);
    }
    return 0;
}

