import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int type = sc.nextInt();
            String s = sc.next();
            int n = s.length();
            int boys = 0, girls = 0;
            for (int i = 0; i < n; i++) {
                if (s.charAt(i) == 'B') boys++;
                else girls++;
            }
            if (Math.abs(boys - girls) > 1) {
                System.out.println(-1);
                continue;
            }
            int cost = 0;
            char[] arr = s.toCharArray();
            for (int i = 0; i < n; i++) {
                if (i % 2 == 0 && arr[i] != 'B' || i % 2 == 1 && arr[i] != 'G') {
                    for (int j = i + 1; j < n; j++) {
                        if (i % 2 == 0 && arr[j] == 'B' || i % 2 == 1 && arr[j] == 'G') {
                            char temp = arr[i];
                            arr[i] = arr[j];
                            arr[j] = temp;
                            if(type == 1) cost += (j - i);
                            else if(type == 2) cost += (j - i) * (j - i);
                            break;
                        }
                    }
                }
            }
            System.out.println(cost);
        }
    }
}

